class Solution:
    def findIntegers(self, n: int) -> int:
        dp = [0] * 31
        dp[0] = dp[1] = 1
        for i in range(2, 31):
            dp[i] = dp[i-1] + dp[i-2]
        ans, last = 0, 0
        for i in range(30, -1, -1):
            if (n >> i) & 1:
                ans += dp[i]
                if last:
                    return ans
                last = 1
            else:
                last = 0
        return ans + 1

